class Solution {
public:
    int minimumChanges(string s, int k) {
        int result = INT_MAX;
        int count = 0;
        for (int i = 0; i < s.length(); i += k) {
            int changes = 0;
            for (int j = 0; j < k; j++) {
                if (s[i + j] == s[i]) {
                    changes++;
                }
            }
            result = min(result, changes);
            count += changes;
        }
        return result + count;
    }
};
```

